arguments.command:
cat > /tmp/stackalloc_test/Program.cs << 'EOF'
Span<nint> signedSpan = stackalloc nint[4];
Span<nuint> unsignedSpan = stackalloc nuint[4];

for (int i = 0; i < 4; i++)
{
    signedSpan[i] = (nint)(i * -10);
    unsignedSpan[i] = (nuint)(i * 10);
}

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");
Console.WriteLine($"signedSpan: [{string.Join(", ", signedSpan.ToArray())}]");
Console.WriteLine($"unsignedSpan: [{string.Join(", ", unsignedSpan.ToArray())}]");
EOF
